/* ============================================================================
   KOMPONEN UTAMA APP (PENGURUSAN LOGIN)
   ============================================================================ */
export default function App() {
  const [currentUser, setCurrentUser] = useState(null);
  const [loginEmail, setLoginEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');

  const handleLogin = (e) => {
    e.preventDefault();
    setLoading(true);
    setErrorMsg('');
    setTimeout(() => {
      const user = MOCK_USERS_DB[loginEmail.toLowerCase().trim()];
      if (user) {
        setCurrentUser(user);
      } else {
        setErrorMsg('Sila gunakan admin@arconnect.my atau user@gmail.com untuk tujuan demo.');
      }
      setLoading(false);
    }, 800);
  };

  const onLogout = () => {
    setCurrentUser(null);
    setLoginEmail('');
  };

  // Skrin Log Masuk
  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 font-sans">
        <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl shadow-slate-200 border border-white p-10">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-green-500 rounded-2xl flex items-center justify-center mx-auto mb-4 rotate-3 shadow-lg shadow-green-200">
              <Zap size={32} className="text-white fill-current" />
            </div>
            <h1 className="text-3xl font-black tracking-tighter text-slate-900">AR CONNECT</h1>
            <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-1">Professional WA Engine</p>
          </div>

          <div className="bg-slate-50 p-4 rounded-2xl mb-8 border border-slate-100 text-center">
            <p className="text-xs font-medium text-slate-500 leading-relaxed">
              Sila gunakan emel <b>admin@arconnect.my</b> (Admin) atau <b>user@gmail.com</b> (Klien).
            </p>
          </div>

          {errorMsg && (
            <div className="p-4 rounded-2xl mb-6 text-xs font-bold flex items-center gap-2 bg-red-50 text-red-500">
              <AlertCircle size={16} /> {errorMsg}
            </div>
          )}

          <form onSubmit={handleLogin} className="space-y-4">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Account Email</label>
              <input 
                type="email" 
                value={loginEmail} 
                onChange={(e) => setLoginEmail(e.target.value)} 
                placeholder="e.g. admin@arconnect.my" 
                required 
                className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-slate-50 focus:border-green-500 font-bold text-sm transition-all" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Password</label>
              <input 
                type="password" 
                placeholder="••••••••" 
                required 
                className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-slate-50 focus:border-green-500 font-bold text-sm transition-all" 
              />
            </div>
            <button disabled={loading} type="submit" className="w-full py-5 bg-green-500 text-white rounded-2xl font-black hover:bg-green-600 transition shadow-xl shadow-green-100 mt-4 uppercase tracking-widest flex justify-center items-center gap-2">
              {loading ? <Loader2 className="animate-spin" /> : <LogIn size={20} />} Log Masuk
            </button>
          </form>
          <p className="text-center text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mt-10">
            &copy; 2024 AR CONNECT TECHNOLOGY
          </p>
        </div>
      </div>
    );
  }

  // Pengesanan Portal Admin / User
  if (currentUser.role === 'admin') {
    return <AdminPortal currentUser={currentUser} onLogout={onLogout} />;
  }

  return <UserPortal currentUser={currentUser} onLogout={onLogout} />;
}
